// Bug 1: Kondisi perulangan salah — perulangan tidak mencapai 10
// Bug 2: Pengecekan ganjil terbalik
// Bug 3: Penambahan counter tidak tepat

for (let i = 1; i < 10; i++) {
  if (i % 2 === 0) {
    console.log(i);
  }
  i += 1;
}

solution:
for (let i = 1; i <= 10; i++) {
  if (i % 2 !== 0) {
    console.log(i);
  }
}
